rizes!","is_fee_based":false,"is_daily":false,"fee_amount_cents":null,"valid_from":"2026-05-26","valid_until":"2026-09-08","source_url":"https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-services/services-standard-assets/ops-comm/wdw-csd/resort-collateral/recreation/fy26-q2/WL_Aframe_Recreation-0326.pdf"},{"activity_catalog_id":"af1323c9-8364-8b7f-d07a-1b95e8a95609","calendar_group_key":"wilderness-lodge","canonical_name":"Wonders Of The Lodge Art & Architecture Tour","normalized_name":"wonders-of-the-lodge-art-architecture-tour","default_category":"other","section":"Resort Activities","location":"Meet near Resort Lobby Fireplace","schedule_text":"Daily at 9:00am","description":"Join us for a fascinating, one-hour walking tour that highlights the architecture and theme of the Resort. Learn about the art, artifacts and classic craftsmanship that celebrate the majesty of the wilderness.","is_fee_based":false,"is_daily":true,"fee_amount_cents":null,"valid_from":"2026-05-26","valid_until":"2026-09-08","source_url":"https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-services/services-standard-assets/ops-comm/wdw-csd/resort-collateral/recreation/fy26-q2/WL_Aframe_Recreation-0326.pdf"}]$payload$::jsonb) as d(
