insert into activity_catalog (
  id,
  calendar_group_key,
  canonical_name,
  normalized_name,
  default_category,
  is_deprecated
)
select
  activity_catalog_id,
  calendar_group_key,
  canonical_name,
  normalized_name,
  default_category::activity_category,
  false
from desired_activity_rows
on conflict (calendar_group_key, normalized_name) do update
set
  canonical_name = excluded.canonical_name,
  default_category = excluded.default_category,
  is_deprecated = false;

insert into resort_activity_editions (
  activity_catalog_id,
  edition_id,
  name,
  category,
  section,
  location,
  schedule_text,
  description,
  is_fee_based,
  is_daily,
  fee_amount_cents,
  parse_confidence,
  needs_review,
  valid_from,
  valid_until,
  is_active
)
select
  ac.id,
  acg.current_edition_id,
  d.canonical_name,
  d.default_category::activity_category,
  d.section,
  d.location,
  d.schedule_text,
  d.description,
  d.is_fee_based,
  d.is_daily,
  d.fee_amount_cents,
  1.0,
  false,
  d.valid_from,
  d.valid_until,
  true
from desired_activity_rows d
join activity_catalog ac
  on ac.calendar_group_key = d.calendar_group_key
 and ac.normalized_name = d.normalized_name
join activity_calendar_groups acg
  on acg.calendar_group_key = d.calendar_group_key
on conflict (activity_catalog_id, edition_id) do update
set
  name = excluded.name,
  category = excluded.category,
  section = excluded.section,
  location = excluded.location,
  schedule_text = excluded.schedule_text,
  description = excluded.description,
  is_fee_based = excluded.is_fee_based,
  is_daily = excluded.is_daily,
  fee_amount_cents = excluded.fee_amount_cents,
  parse_confidence = excluded.parse_confidence,
  needs_review = excluded.needs_review,
  valid_from = excluded.valid_from,
  valid_until = excluded.valid_until,
  is_active = true;

update resort_activity_editions rae
set is_active = false
from activity_catalog ac
join activity_calendar_groups acg
  on acg.calendar_group_key = ac.calendar_group_key
where rae.activity_catalog_id = ac.id
  and rae.edition_id = acg.current_edition_id
  and rae.is_active = true
  and not exists (
    select 1
    from desired_activity_rows d
    where d.calendar_group_key = ac.calendar_group_key
      and d.normalized_name = ac.normalized_name
  );

update activity_catalog ac
set is_deprecated = true
where exists (
    select 1
    from activity_calendar_groups acg
    where acg.calendar_group_key = ac.calendar_group_key
  )
  and not exists (
    select 1
    from desired_activity_rows d
    where d.calendar_group_key = ac.calendar_group_key
      and d.normalized_name = ac.normalized_name
  );

insert into resort_activities (
  id,
  calendar_group_key,
  name,
  normalized_name,
  category,
  section,
  location,
  schedule_text,
  description,
  is_fee_based,
  is_daily,
  source_pdf_url
)
select
  ac.id,
  d.calendar_group_key,
  d.canonical_name,
  d.normalized_name,
  d.default_category::activity_category,
  d.section,
  d.location,
  d.schedule_text,
  d.description,
  d.is_fee_based,
  d.is_daily,
  d.source_url
from desired_activity_rows d
join activity_catalog ac
  on ac.calendar_group_key = d.calendar_group_key
 and ac.normalized_name = d.normalized_name
on conflict (calendar_group_key, normalized_name) do update
set
  name = excluded.name,
  category = excluded.category,
  section = excluded.section,
  location = excluded.location,
  schedule_text = excluded.schedule_text,
  description = excluded.description,
  is_fee_based = excluded.is_fee_based,
  is_daily = excluded.is_daily,
  source_pdf_url = excluded.source_pdf_url;

delete from resort_activities ra
where exists (
    select 1
    from activity_calendar_groups acg
    where acg.calendar_group_key = ra.calendar_group_key
  )
  and not exists (
    select 1
    from desired_activity_rows d
    where d.calendar_group_key = ra.calendar_group_key
      and d.normalized_name = ra.normalized_name
  );

select 'desired_rows' as metric, count(*)::text as value from desired_activity_rows
union all
select 'active_current_edition_rows', count(*)::text
from resort_activity_editions rae
join activity_catalog ac on ac.id = rae.activity_catalog_id
join activity_calendar_groups acg
  on acg.calendar_group_key = ac.calendar_group_key
 and acg.current_edition_id = rae.edition_id
where rae.is_active = true
union all
select 'legacy_rows', count(*)::text
from resort_activities;

commit;
